# -*- coding: utf-8 -*-
import streamlit as st

# Perguntas e opções diretamente no script
perguntas = [
    {
        "pergunta": "Qual desses alimentos é uma fonte saudável de proteína?",
        "opcoes": [
            {"texto": "Frango grelhado", "imagem": "data:image/jpeg;base64,", "correta": True},
            {"texto": "Batata frita", "imagem": "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQdS8MC7rTqEFQmJOtLW77g3I0ipUvLvshbhw&s", "correta": False},
            {"texto": "Refrigerante", "imagem": "data:image/jpeg;base64,", "correta": False},
        ],
        "mensagem_retorno": "Proteínas são essenciais para a construção muscular!",
        "imagem_acerto": "https://media3.giphy.com/media/v1.Y2lkPTc5MGI3NjExM2twdHkyMnQ0NmNseTEyOWtucWtkYnJ4YTRybTNzbjE4eWNnZ3U0YSZlcD12MV9naWZzX3NlYXJjaCZjdD1n/6gggcXvB0KJtZmgSjv/200.webp",
        "imagem_erro": "https://media3.giphy.com/media/v1.Y2lkPTc5MGI3NjExY2Q5NjI1dGUyNDJrN3FvcGlmZWYzc2syOGM0YmswNXUxcGRxMXhubSZlcD12MV9naWZzX3NlYXJjaCZjdD1n/Awa5Y73PQNUS7HEdyu/giphy.webp"
    },
    {
        "pergunta": "Qual é a melhor fonte de fibras?",
        "opcoes": [
            {"texto": "Maçã", "imagem": "data:image/jpeg;base64,", "correta": True},
            {"texto": "Sorvete", "imagem": "data:image/jpeg;base64,", "correta": False},
            {"texto": "Pizza", "imagem": "data:image/jpeg;base64,", "correta": False},
        ],
        "mensagem_retorno": "As fibras ajudam na digestão e na saúde intestinal.",
        "imagem_acerto": "https://media1.giphy.com/media/v1.Y2lkPTc5MGI3NjExM2twdHkyMnQ0NmNseTEyOWtucWtkYnJ4YTRybTNzbjE4eWNnZ3U0YSZlcD12MV9naWZzX3NlYXJjaCZjdD1n/ifjxbr48JX992DRMiX/200.webp",
        "imagem_erro": "https://media4.giphy.com/media/v1.Y2lkPTc5MGI3NjExY2Q5NjI1dGUyNDJrN3FvcGlmZWYzc2syOGM0YmswNXUxcGRxMXhubSZlcD12MV9naWZzX3NlYXJjaCZjdD1n/J8hKdpLGKCFc3K0OE1/giphy.webp"
    },
    {
        "pergunta": "Qual bebida é a mais saudável?",
        "opcoes": [
            {"texto": "Água", "imagem": "data:image/jpeg;base64,", "correta": True},
            {"texto": "Refrigerante", "imagem": "data:image/jpeg;base64,", "correta": False},
            {"texto": "Suco de caixinha", "imagem": "data:image/png;base64,", "correta": False},
        ],
        "mensagem_retorno": "A água mantém o corpo hidratado e saudável.",
        "imagem_acerto": "https://media1.giphy.com/media/v1.Y2lkPTc5MGI3NjExM2twdHkyMnQ0NmNseTEyOWtucWtkYnJ4YTRybTNzbjE4eWNnZ3U0YSZlcD12MV9naWZzX3NlYXJjaCZjdD1n/yeVFdAno8dcxLEps9Q/giphy.webp",
        "imagem_erro": "https://media0.giphy.com/media/v1.Y2lkPWVjZjA1ZTQ3MHJ2dWtpem5keG52OGU2a3l0MXdrbDZjeWdvZTVwZnRrZ3M4eGwyaiZlcD12MV9naWZzX3NlYXJjaCZjdD1n/3o7WTDH9gYo71TurPq/200.webp"
    }
]

st.title("Jogo Educativo de Alimentação Saudável")

for idx, pergunta in enumerate(perguntas):
    st.subheader(f"Pergunta {idx + 1}")
    st.write(pergunta["pergunta"])
    
    # Cria 3 colunas para as opções
    col1, col2, col3 = st.columns(3)
    opcoes = pergunta["opcoes"]
    
    # Função para verificar resposta
    def verificar_resposta(opcao):
        if opcao["correta"]:
            st.success("✅ Acertou!")
            st.image(pergunta["imagem_acerto"], width=200)
        else:
            st.error("❌ Errou!")
            st.image(pergunta["imagem_erro"], width=200)
        st.info(pergunta["mensagem_retorno"])
    
    if col1.button(opcoes[0]["texto"], key=f"{idx}_0"):
        verificar_resposta(opcoes[0])
    col1.image(opcoes[0]["imagem"], width=150)
    
    if col2.button(opcoes[1]["texto"], key=f"{idx}_1"):
        verificar_resposta(opcoes[1])
    col2.image(opcoes[1]["imagem"], width=150)
    
    if col3.button(opcoes[2]["texto"], key=f"{idx}_2"):
        verificar_resposta(opcoes[2])
    col3.image(opcoes[2]["imagem"], width=150)